 1	import React, { FC, useState } from 'react';
 2	
 3	import { TemplateParameter } from '@kubevirt-ui/kubevirt-api/console';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Checkbox, ExpandableSection, FormGroup, TextInput } from '@patternfly/react-core';
 6	
 7	import ParameterValueEditor from './ParameterValueEditor';
 8	
 9	type ParameterEditorProps = {
10	  isEditDisabled?: boolean;
11	  onChange: (parameter: TemplateParameter) => void;
12	  parameter: TemplateParameter;
13	};
14	
15	const ParameterEditor: FC<ParameterEditorProps> = ({ isEditDisabled, onChange, parameter }) => {
16	  const { t } = useKubevirtTranslation();
17	  const [isExpanded, setExpanded] = useState(true);
18	
19	  return (
20	    <ExpandableSection
21	      toggleContent={
22	        <>
23	          <strong>{t('Name')} </strong> {parameter.name}
24	        </>
25	      }
26	      isExpanded={isExpanded}
27	      isIndented
28	      onToggle={(_, expand: boolean) => setExpanded(expand)}
29	    >
30	      <FormGroup fieldId={`${parameter.name}-required`}>
31	        <Checkbox
32	          id={`${parameter.name}-required`}
33	          isChecked={parameter.required}
34	          isDisabled={isEditDisabled}
35	          label={t('Required')}
36	          onChange={(_event, required) => onChange({ ...parameter, required })}
37	        />
38	      </FormGroup>
39	      <FormGroup fieldId={`${parameter.name}-description`} label={t('Description')}>
40	        <TextInput
41	          id={`${parameter.name}-description`}
42	          isDisabled={isEditDisabled}
43	          onChange={(_event, description) => onChange({ ...parameter, description })}
44	          value={parameter.description}
45	        />
46	      </FormGroup>
47	      <ParameterValueEditor
48	        isEditDisabled={isEditDisabled}
49	        onChange={onChange}
50	        parameter={parameter}
51	      />
52	    </ExpandableSection>
53	  );
54	};
55	
56	export default ParameterEditor;

